def compute_score():
    from pptx import Presentation
    slide_num = 6
    expected_text = 'Determining healthy weight for children requires precise measurement tools'
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[slide_num-1]
    found = False
    underlined = False
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue
        for para in shape.text_frame.paragraphs:
            text = para.text.strip()
            if expected_text.strip().lower() == text.lower():
                found = True
                for run in para.runs:
                    if run.text.strip().lower() == expected_text.strip().lower():
                        if run.font.underline:
                            underlined = True
                        break
                # If no runs match text exactly, check all runs in para
                if not underlined:
                    if any(run.font.underline for run in para.runs):
                        underlined = True
                break
    if not found:
        return "Bullet text not found on slide 6 for underline check.", 0.0
    if underlined:
        return "Bullet is underlined.", 1.0
    else:
        return "Bullet is not underlined.", 0.0

